#include <iostream>
#include <vector>
#include <unordered_map>
#include <climits>

using namespace std;

struct Node {
    int val;
    Node* next;
    Node* prev;
    Node(int x) : val(x), next(nullptr), prev(nullptr) {}
};

class Solution {
public:
    Node* reorderList(Node* head) {
        if (head == NULL || head->next == NULL) return head;
        unordered_map<int, vector<Node*>> map;
        Node* current = head;
        while (current != NULL) {
            map[current->val].push_back(current);
            current = current->next;
        }
        current = head;
        Node* prev = NULL;
        while (current != NULL) {
            for (auto node : map[current->val]) {
                if (prev != NULL) {
                    prev->next = node;
                    node->prev = prev;
                } else {
                    head = node;
                }
                if (node->next != NULL) {
                    map[node->next->val].erase(find(map[node->next->val].begin(), map[node->next->val].end(), node));
                }
                current = node->next;
                break;
            }
            prev = node;
        }
        return head;
    }
};

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> values(n);
        for (int i = 0; i < n; i++) {
            cin >> values[i];
        }
        Solution s;
        Node* head = NULL;
        Node* current = NULL;
        for (int value : values) {
            Node* node = new Node(value);
            if (head == NULL) {
                head = node;
                current = node;
            } else {
                current->next = node;
                node->prev = current;
                current = node;
            }
        }
        s.reorderList(head);
        Node* current_node = head;
        while (current_node) {
            cout << current_node->val << ' ';
            current_node = current_node->next;
        }
        cout << '\n';
    }
    return 0;
}
